// Alert Dedup + Trend Detection using Static Data
const state = $getWorkflowStaticData('global');
const data = $input.first().json;
const now = Date.now();

// Initialize state
if (!state.lastSeverity) state.lastSeverity = 'HEALTHY';
if (!state.lastAlertTime) state.lastAlertTime = 0;
if (!state.lastIssueKeys) state.lastIssueKeys = [];
if (!state.lastMetrics) state.lastMetrics = {};
if (!state.cachedHealth) state.cachedHealth = {};

// Cache health for /status command
state.cachedHealth = {
  severity: data.severity,
  summary: data.summary,
  timestamp: data.timestamp,
  issues: data.issues,
  metrics: data.metrics,
  cached_at: new Date().toISOString()
};

// Generate issue fingerprint for dedup
const currentKeys = (data.issues || []).map(i => i.component + ':' + i.severity).sort().join(',');
const prevKeys = (state.lastIssueKeys || []).join(',');

// Determine if we should alert
let shouldAlert = false;
let alertReason = '';

if (data.severity === 'CRITICAL') {
  if (state.lastSeverity !== 'CRITICAL') {
    shouldAlert = true; alertReason = 'NEW_CRITICAL';
  } else if (currentKeys !== prevKeys) {
    shouldAlert = true; alertReason = 'CHANGED_ISSUES';
  } else if (now - state.lastAlertTime > 7200000) { // 2h
    shouldAlert = true; alertReason = 'CRITICAL_PERSISTENT_2H';
  }
} else if (data.severity === 'WARNING') {
  if (state.lastSeverity === 'CRITICAL') {
    shouldAlert = true; alertReason = 'RECOVERY_TO_WARNING';
  } else if (state.lastSeverity !== 'WARNING') {
    shouldAlert = true; alertReason = 'NEW_WARNING';
  } else if (currentKeys !== prevKeys) {
    shouldAlert = true; alertReason = 'CHANGED_ISSUES';
  } else if (now - state.lastAlertTime > 21600000) { // 6h
    shouldAlert = true; alertReason = 'WARNING_PERSISTENT_6H';
  }
} else if (data.severity === 'HEALTHY') {
  if (state.lastSeverity === 'CRITICAL' || state.lastSeverity === 'WARNING') {
    shouldAlert = true; alertReason = 'RECOVERY';
  }
  // HEALTHY = silent (no spam)
}

// Trend detection
const trends = [];
const prev = state.lastMetrics || {};
if (prev.ram_available_mb && data.metrics.ram_available_mb) {
  const delta = prev.ram_available_mb - data.metrics.ram_available_mb;
  if (delta > 500) trends.push('RAM dropping: -' + delta + 'MB');
}
if (prev.disk_root_percent && data.metrics.disk_root_percent) {
  const delta = data.metrics.disk_root_percent - prev.disk_root_percent;
  if (delta > 5) trends.push('Disk growing: +' + delta + '%');
}
if (trends.length > 0 && !shouldAlert && data.severity !== 'HEALTHY') {
  shouldAlert = true; alertReason = 'TREND_DETECTED';
}

// Update state
if (shouldAlert) state.lastAlertTime = now;
state.lastSeverity = data.severity;
state.lastIssueKeys = (data.issues || []).map(i => i.component + ':' + i.severity).sort();
state.lastMetrics = data.metrics || {};

return [{ json: {
  ...data,
  should_alert: shouldAlert,
  alert_reason: alertReason,
  trends: trends,
  previous_severity: state.lastSeverity
}}];

