const data = $input.first().json;
const logLine = JSON.stringify({
  timestamp: new Date().toISOString(),
  severity: data.severity,
  summary: data.summary,
  should_alert: data.should_alert,
  alert_reason: data.alert_reason,
  issues_count: (data.issues || []).length,
  ram_mb: (data.metrics || {}).ram_available_mb,
  disk_pct: (data.metrics || {}).disk_root_percent,
  cpu_load: (data.metrics || {}).cpu_load_1m
}).replace(/'/g, "'\\''");
return [{ json: { ...data, _logLine: logLine } }];

// Zero Trust + Rate Limiter + Command Router
// Webhook receives Telegram update as body
const body = $input.first().json.body || $input.first().json;
const msg = body.message || {};
const fromId = msg.from ? msg.from.id : 0;
const chatId = msg.chat ? msg.chat.id : 0;
const text = (msg.text || '').trim();

// Zero Trust: verify numeric ID
if (fromId !== 501092522) {
  return [{ json: { type: 'UNAUTHORIZED', fromId, text } }];
}

// Rate Limiter: max 10 commands per minute
const state = $getWorkflowStaticData('global');
if (!state.cmdTimes) state.cmdTimes = [];
const now = Date.now();
state.cmdTimes = state.cmdTimes.filter(t => now - t < 60000);
if (state.cmdTimes.length >= 10) {
  return [{ json: { type: 'RATE_LIMITED', chatId, text } }];
}
state.cmdTimes.push(now);

// Route command
if (text.startsWith('/approve')) {
  const cmd = text.replace('/approve', '').trim();
  return [{ json: { type: 'approve', command: cmd, chatId, source: 'approve' } }];
} else if (text === '/status') {
  return [{ json: { type: 'status', chatId } }];
} else if (text === '/check') {
  return [{ json: { type: 'check', chatId } }];
} else if (text.startsWith('/maintenance')) {
  const task = text.replace('/maintenance', '').trim();
  return [{ json: { type: 'maintenance', task, chatId } }];
} else if (text === '/help') {
  return [{ json: { type: 'help', chatId } }];
} else {
  return [{ json: { type: 'freeform', prompt: text, chatId, source: 'freeform' } }];
}

// Return cached health status from Static Data
const state = $getWorkflowStaticData('global');
const cached = state.cachedHealth || { severity: 'UNKNOWN', summary: 'No health check has run yet', timestamp: 'N/A' };
const chatId = $input.first().json.chatId || 501092522;

const issueText = (cached.issues && cached.issues.length > 0)
  ? cached.issues.map((i, idx) => (idx+1) + '. [' + i.component + '] ' + i.detail).join('\n')
  : 'No issues';

const m = cached.metrics || {};
const metricsText = 'RAM: ' + (m.ram_available_mb || '?') + 'MB | Disk: ' + (m.disk_root_percent || '?') + '% | CPU: ' + (m.cpu_load_1m || '?') + ' | Docker: ' + (m.containers_healthy || '?') + '/' + (m.containers_total || '?');

return [{ json: { chatId, text: '📊 *S1 VPS Guard — Status (cached)*\n\n*Severity:* ' + cached.severity + '\n*Summary:* ' + cached.summary + '\n*Last check:* ' + cached.timestamp + '\n\n' + issueText + '\n\n' + metricsText } }];

const data = $input.first().json;
const chatId = $('Route Command').first().json.chatId || 501092522;

const icon = data.severity === 'CRITICAL' ? '🚨' : data.severity === 'WARNING' ? '⚠️' : '✅';
const issueText = (data.issues && data.issues.length > 0)
  ? data.issues.map((i, idx) => (idx+1) + '. [' + i.component + '] ' + i.detail).join('\n')
  : 'No issues';

const m = data.metrics || {};
const metricsText = 'RAM: ' + (m.ram_available_mb || '?') + 'MB | Disk: ' + (m.disk_root_percent || '?') + '% | CPU: ' + (m.cpu_load_1m || '?') + ' | Docker: ' + (m.containers_healthy || '?') + '/' + (m.containers_total || '?');

return [{ json: { chatId, text: icon + ' *S1 VPS Guard — Check Result*\n\n*Severity:* ' + data.severity + '\n*Summary:* ' + data.summary + '\n\n' + issueText + '\n\n📊 ' + metricsText } }];

const input = $input.first().json;
const presets = { 'docker-prune': 'docker system prune -af --filter "until=72h"', 'log-rotate': 'find /var/log -name "*.log" -size +100M -exec truncate -s 0 {} \\;', 'backup-now': 'bash /usr/local/bin/aurenix-backup-pro.sh', 'ssl-check': 'certbot certificates', 'disk-report': 'du -sh /data/* | sort -rh' };
const cmd = presets[input.task];
if (!cmd) { return [{ json: { command: 'BLOCKED', explanation: 'Unknown preset: ' + input.task + '. Available: ' + Object.keys(presets).join(', '), chatId: input.chatId, source: 'maintenance' } }]; }
return [{ json: { command: cmd, chatId: input.chatId, source: 'maintenance' } }];

try {
  let raw = $input.first().json.text || $input.first().json.output || '';
  if (raw.includes('```json')) raw = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '');
  else if (raw.includes('```')) raw = raw.replace(/```\n?/g, '');
  const parsed = JSON.parse(raw.trim());
  const chatId = $('Route Command').first().json.chatId || 501092522;
  return [{ json: { command: parsed.command, explanation: parsed.explanation, chatId, source: 'freeform' } }];
} catch (e) {
  const chatId = $('Route Command').first().json.chatId || 501092522;
  return [{ json: { command: 'BLOCKED', explanation: 'AI parse error: ' + e.message, chatId, source: 'freeform' } }];
}

// JS Validator V3 — Unified Security Shield
const allowedPrefixes = [
  'docker ps', 'docker stats', 'docker logs', 'docker restart', 'docker start',
  'docker stop', 'docker inspect', 'docker system df', 'docker system prune',
  'docker compose', 'docker top', 'docker exec',
  'free', 'uptime', 'df', 'top -b', 'vmstat', 'iostat',
  'ls', 'tail', 'cat', 'head', 'wc', 'du -sh', 'find /data',
  'ss ', 'ss -', 'netstat', 'ping -c', 'dig ', 'curl http://localhost', 'curl -s http://localhost',
  'curl http://10.0.2.3', 'curl -s http://10.0.2.3',
  'systemctl status', 'systemctl restart', 'journalctl',
  'pg_isready', 'psql -c',
  'fail2ban-client status',
  'python scripts/', 'python3 scripts/',
  'bash /usr/local/bin/aurenix-backup-pro.sh',
  'certbot certificates', 'certbot renew',
  'apt list --upgradable',
  'test ', 'echo ', 'date', 'whoami', 'id',
  'htop', 'iotop'
];

const blockedKeywords = [
  'rm -rf', 'rm -r /', 'rm /', 'dd if=', 'mkfs', '> /dev', 'shutdown', 'reboot', 'halt',
  'passwd', 'chmod 777', 'chmod -R 777', 'chown -R root',
  'DROP ', 'DELETE FROM', 'TRUNCATE', 'ALTER TABLE',
  'curl | bash', 'wget | bash', 'curl | sh', 'wget | sh',
  'iptables -F', 'ufw disable', 'ufw reset',
  '&& rm', '; rm', '| rm', '| bash', '| sh',
  'eval ', 'exec ', 'python -c', 'python3 -c', 'node -e',
  'ssh ', 'scp ', 'rsync', 'nc -l', 'ncat', 'socat',
  'base64 -d | bash', 'base64 -d | sh',
  '/etc/shadow', '/etc/passwd', '/etc/sudoers',
  'crontab -r', 'crontab -e',
  'kill -9 1', 'killall'
];

const input = $input.first().json;
const cmd = (input.command || '').trim();
const chatId = input.chatId || 501092522;
const source = input.source || 'unknown';

if (!cmd || cmd === 'auto' || cmd === 'BLOCKED') {
  return [{ json: { safe: false, command: cmd, reason: input.explanation || 'Empty or blocked command', chatId, source } }];
}

const isAllowed = allowedPrefixes.some(p => cmd.startsWith(p));
const forbidden = blockedKeywords.find(k => cmd.toLowerCase().includes(k.toLowerCase()));

if (isAllowed && !forbidden) {
  return [{ json: { safe: true, command: cmd, chatId, source } }];
} else {
  const reason = forbidden ? 'Blocked keyword: ' + forbidden : 'Not in allowed prefixes';
  return [{ json: { safe: false, command: cmd, reason, chatId, source } }];
}

